CREATE TYPE "UserRole" AS ENUM ('CUSTOMER','CASHIER','BUSINESS_ADMIN','BUSINESS_OWNER','MICLUB_ADMIN');
CREATE TYPE "UserStatus" AS ENUM ('ACTIVE','INACTIVE','SUSPENDED');
CREATE TYPE "BusinessStatus" AS ENUM ('active','suspended','grace_period','cancelled');
CREATE TYPE "MembershipStatus" AS ENUM ('active','inactive');
CREATE TYPE "ProgramStatus" AS ENUM ('draft','active','archived');
CREATE TYPE "AccumulationType" AS ENUM ('purchase_count','visit_count','amount_spent','points');
CREATE TYPE "CycleStatus" AS ENUM ('active','completed','cancelled');
CREATE TYPE "TransactionType" AS ENUM ('purchase','visit','manual_points','amount');
CREATE TYPE "TransactionStatus" AS ENUM ('valid','cancelled');
CREATE TYPE "RewardStatus" AS ENUM ('available','redeemed','expired','cancelled');

CREATE TABLE "users" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL,"email" TEXT NOT NULL,"phone" TEXT NOT NULL,"password_hash" TEXT NOT NULL,"birth_date" DATE,"rut" TEXT,"role" "UserRole" NOT NULL DEFAULT 'CUSTOMER',"status" "UserStatus" NOT NULL DEFAULT 'ACTIVE',"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL);
CREATE TABLE "auth_sessions" ("id" TEXT PRIMARY KEY,"refresh_token_hash" TEXT NOT NULL,"expires_at" TIMESTAMP(3) NOT NULL,"revoked_at" TIMESTAMP(3),"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"user_id" TEXT NOT NULL);
CREATE TABLE "plans" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL,"monthly_price" DECIMAL(12,2) NOT NULL DEFAULT 0,"customer_limit" INTEGER NOT NULL DEFAULT 500,"collaborator_limit" INTEGER NOT NULL DEFAULT 3,"features" JSONB NOT NULL DEFAULT '[]',"active" BOOLEAN NOT NULL DEFAULT true,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL);
CREATE TABLE "businesses" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL,"slug" TEXT NOT NULL,"business_type" TEXT NOT NULL,"rut_business" TEXT,"owner_user_id" TEXT NOT NULL,"phone" TEXT NOT NULL,"email" TEXT NOT NULL,"address" TEXT NOT NULL,"logo_url" TEXT,"status" "BusinessStatus" NOT NULL DEFAULT 'active',"plan_id" TEXT,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL);
CREATE TABLE "business_users" ("id" TEXT PRIMARY KEY,"business_id" TEXT NOT NULL,"user_id" TEXT NOT NULL,"role" "UserRole" NOT NULL,"status" "MembershipStatus" NOT NULL DEFAULT 'active',"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "loyalty_programs" ("id" TEXT PRIMARY KEY,"business_id" TEXT NOT NULL,"name" TEXT NOT NULL,"accumulation_type" "AccumulationType" NOT NULL,"target_value" DECIMAL(14,2) NOT NULL,"reward_description" TEXT NOT NULL,"reward_expiration_days" INTEGER,"version" INTEGER NOT NULL DEFAULT 1,"status" "ProgramStatus" NOT NULL DEFAULT 'draft',"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL);
CREATE TABLE "customer_businesses" ("id" TEXT PRIMARY KEY,"customer_user_id" TEXT NOT NULL,"business_id" TEXT NOT NULL,"joined_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"status" "MembershipStatus" NOT NULL DEFAULT 'active');
CREATE TABLE "cycles" ("id" TEXT PRIMARY KEY,"customer_user_id" TEXT NOT NULL,"business_id" TEXT NOT NULL,"loyalty_program_id" TEXT NOT NULL,"current_value" DECIMAL(14,2) NOT NULL DEFAULT 0,"target_value" DECIMAL(14,2) NOT NULL,"status" "CycleStatus" NOT NULL DEFAULT 'active',"started_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"completed_at" TIMESTAMP(3),"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL);
CREATE TABLE "transactions" ("id" TEXT PRIMARY KEY,"cycle_id" TEXT NOT NULL,"business_id" TEXT NOT NULL,"customer_user_id" TEXT NOT NULL,"performed_by_user_id" TEXT NOT NULL,"transaction_type" "TransactionType" NOT NULL,"previous_value" DECIMAL(14,2) NOT NULL,"value_added" DECIMAL(14,2) NOT NULL,"amount_optional" DECIMAL(14,2),"status" "TransactionStatus" NOT NULL DEFAULT 'valid',"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"cancelled_at" TIMESTAMP(3),"cancelled_by_user_id" TEXT);
CREATE TABLE "rewards" ("id" TEXT PRIMARY KEY,"cycle_id" TEXT NOT NULL,"business_id" TEXT NOT NULL,"customer_user_id" TEXT NOT NULL,"reward_description" TEXT NOT NULL,"status" "RewardStatus" NOT NULL DEFAULT 'available',"generated_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"expires_at" TIMESTAMP(3),"redeemed_at" TIMESTAMP(3),"redeemed_by_user_id" TEXT);
CREATE TABLE "audit_logs" ("id" TEXT PRIMARY KEY,"user_id" TEXT NOT NULL,"business_id" TEXT,"action" TEXT NOT NULL,"entity_type" TEXT NOT NULL,"entity_id" TEXT NOT NULL,"metadata" JSONB,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);

CREATE UNIQUE INDEX "users_email_key" ON "users"("email"); CREATE UNIQUE INDEX "users_rut_key" ON "users"("rut"); CREATE INDEX "auth_sessions_user_id_idx" ON "auth_sessions"("user_id"); CREATE UNIQUE INDEX "plans_name_key" ON "plans"("name"); CREATE UNIQUE INDEX "businesses_slug_key" ON "businesses"("slug"); CREATE UNIQUE INDEX "businesses_rut_business_key" ON "businesses"("rut_business"); CREATE UNIQUE INDEX "business_users_business_id_user_id_key" ON "business_users"("business_id","user_id"); CREATE INDEX "business_users_user_id_idx" ON "business_users"("user_id"); CREATE UNIQUE INDEX "loyalty_programs_business_id_version_key" ON "loyalty_programs"("business_id","version"); CREATE UNIQUE INDEX "loyalty_programs_one_active_idx" ON "loyalty_programs"("business_id") WHERE "status"='active'; CREATE UNIQUE INDEX "customer_businesses_customer_user_id_business_id_key" ON "customer_businesses"("customer_user_id","business_id"); CREATE INDEX "customer_businesses_business_id_idx" ON "customer_businesses"("business_id"); CREATE INDEX "cycles_customer_user_id_business_id_status_idx" ON "cycles"("customer_user_id","business_id","status"); CREATE UNIQUE INDEX "cycles_one_active_idx" ON "cycles"("customer_user_id","business_id") WHERE "status"='active'; CREATE INDEX "transactions_customer_business_status_created_idx" ON "transactions"("customer_user_id","business_id","status","created_at"); CREATE INDEX "rewards_customer_business_status_idx" ON "rewards"("customer_user_id","business_id","status"); CREATE INDEX "audit_logs_business_created_idx" ON "audit_logs"("business_id","created_at");

ALTER TABLE "auth_sessions" ADD CONSTRAINT "auth_sessions_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "businesses" ADD CONSTRAINT "businesses_owner_user_id_fkey" FOREIGN KEY ("owner_user_id") REFERENCES "users"("id") ON UPDATE CASCADE;
ALTER TABLE "businesses" ADD CONSTRAINT "businesses_plan_id_fkey" FOREIGN KEY ("plan_id") REFERENCES "plans"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "business_users" ADD CONSTRAINT "business_users_business_id_fkey" FOREIGN KEY ("business_id") REFERENCES "businesses"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "business_users" ADD CONSTRAINT "business_users_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "loyalty_programs" ADD CONSTRAINT "loyalty_programs_business_id_fkey" FOREIGN KEY ("business_id") REFERENCES "businesses"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "customer_businesses" ADD CONSTRAINT "customer_businesses_customer_user_id_fkey" FOREIGN KEY ("customer_user_id") REFERENCES "users"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "customer_businesses" ADD CONSTRAINT "customer_businesses_business_id_fkey" FOREIGN KEY ("business_id") REFERENCES "businesses"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "cycles" ADD CONSTRAINT "cycles_customer_user_id_fkey" FOREIGN KEY ("customer_user_id") REFERENCES "users"("id") ON UPDATE CASCADE;
ALTER TABLE "cycles" ADD CONSTRAINT "cycles_business_id_fkey" FOREIGN KEY ("business_id") REFERENCES "businesses"("id") ON UPDATE CASCADE;
ALTER TABLE "cycles" ADD CONSTRAINT "cycles_program_id_fkey" FOREIGN KEY ("loyalty_program_id") REFERENCES "loyalty_programs"("id") ON UPDATE CASCADE;
ALTER TABLE "transactions" ADD CONSTRAINT "transactions_cycle_id_fkey" FOREIGN KEY ("cycle_id") REFERENCES "cycles"("id") ON UPDATE CASCADE;
ALTER TABLE "transactions" ADD CONSTRAINT "transactions_business_id_fkey" FOREIGN KEY ("business_id") REFERENCES "businesses"("id") ON UPDATE CASCADE;
ALTER TABLE "transactions" ADD CONSTRAINT "transactions_customer_id_fkey" FOREIGN KEY ("customer_user_id") REFERENCES "users"("id") ON UPDATE CASCADE;
ALTER TABLE "transactions" ADD CONSTRAINT "transactions_performer_id_fkey" FOREIGN KEY ("performed_by_user_id") REFERENCES "users"("id") ON UPDATE CASCADE;
ALTER TABLE "transactions" ADD CONSTRAINT "transactions_canceller_id_fkey" FOREIGN KEY ("cancelled_by_user_id") REFERENCES "users"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "rewards" ADD CONSTRAINT "rewards_cycle_id_fkey" FOREIGN KEY ("cycle_id") REFERENCES "cycles"("id") ON UPDATE CASCADE;
ALTER TABLE "rewards" ADD CONSTRAINT "rewards_business_id_fkey" FOREIGN KEY ("business_id") REFERENCES "businesses"("id") ON UPDATE CASCADE;
ALTER TABLE "rewards" ADD CONSTRAINT "rewards_customer_id_fkey" FOREIGN KEY ("customer_user_id") REFERENCES "users"("id") ON UPDATE CASCADE;
ALTER TABLE "rewards" ADD CONSTRAINT "rewards_redeemer_id_fkey" FOREIGN KEY ("redeemed_by_user_id") REFERENCES "users"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "audit_logs" ADD CONSTRAINT "audit_logs_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON UPDATE CASCADE;
ALTER TABLE "audit_logs" ADD CONSTRAINT "audit_logs_business_id_fkey" FOREIGN KEY ("business_id") REFERENCES "businesses"("id") ON DELETE SET NULL ON UPDATE CASCADE;
